module asyn_fifo
#(
    parameter WIDTH = 8,
    parameter DEPTH = 16
)
(
    input wclk,
    input rclk,
    input wrstn,
    input rrstn,
    input winc,
    input rinc,
    input [WIDTH-1:0] wdata:
);
    parameter WIDTH = 8;
    parameter DEPTH = 16;

    reg [WIDTH-1:0] waddr_bin;
    reg [WIDTH-1:0] raddr_bin;
    reg [WIDTH-1:0] wptr;
    reg [WIDTH-1:0] rptr;
    reg [WIDTH-1:0] wptr_buff;
    reg [WIDTH-1:0] rptr_buff;
    reg [WIDTH-1:0] wptr_syn;
    reg [WIDTH-1:0] rptr_syn;
    reg wen;
    reg ren;

    wire [WIDTH-1:0] rdata;
    reg [WIDTH-1:0] RAM_MEM [0:DEPTH-1];

    always @(posedge wclk or negedge wrstn) begin
        if (!wrstn) begin
            waddr_bin <= 0;
        end else if (winc) begin
            waddr_bin <= waddr_bin + 1;
        end
    end

    always @(posedge rclk or negedge rrstn) begin
        if (!rrstn) begin
            raddr_bin <= 0;
        end else if (rinc) begin
            raddr_bin <= raddr_bin + 1;
        end
    end

    assign wptr = {waddr_bin[WIDTH-1], waddr_bin[WIDTH-1]^waddr_bin[WIDTH-2], waddr_bin[WIDTH-3:0]};
    assign rptr = {raddr_bin[WIDTH-1], raddr_bin[WIDTH-1]^raddr_bin[WIDTH-2], raddr_bin[WIDTH-3:0]};

    always @(posedge wclk or negedge wrstn) begin
        if (!wrstn) begin
            wptr_buff <= 0;
        end else begin
            wptr_buff <= wptr;
        end
    end

    always @(posedge rclk or negedge rrstn) begin
        if (!rrstn) begin
            rptr_buff <= 0;
        end else begin
            rptr_buff <= rptr;
        end
    end

    assign wptr_syn = wptr_buff;
    assign rptr_syn = rptr_buff;

    assign wfull = (wptr == {~rptr_syn[WIDTH-1], rptr_syn[WIDTH-2:0]});
    assign rempty = (rptr_syn == wptr);

    assign wen = wptr_syn;
    assign ren = rptr_syn;

    always @(posedge wclk) begin
        if (wen) begin
            RAM_MEM[waddr_bin] <= wdata;
        end
    end

    always @(posedge rclk) begin
        if (ren) begin
            rdata <= RAM_MEM[raddr_bin];
        end
    end
endmodule
